mapper.select:


     and apply_id = #{applyId}
     and result_type = #{resultType}
     and item_type = #{itemType}
     and item_code = #{itemCode}
     and item_name like concat('%', #{itemName}, '%')
     and result_value = #{resultValue}
     and result_unit = #{resultUnit}
     and reference_range = #{referenceRange}
     and abnormal_flag = #{abnormalFlag}
     and image_url = #{imageUrl}
     and image_find like concat('%', #{imageFind}, '%')
     and diagnosis_opinion like concat('%', #{diagnosisOpinion}, '%')
     and diagnosis_result = #{diagnosisResult}
     and suggestion like concat('%', #{suggestion}, '%')
     and sort = #{sort}
     and status = #{status}
     and doctor_id = #{doctorId}
     and report_time = #{reportTime}

        and exists (
            select 1 from exam_apply ea_scope
            where ea_scope.apply_id = exam_result.apply_id
              and ea_scope.doctor_id = #{params.applyDoctorId}
        )


        and exists (
            select 1 from exam_apply ea_scope
            where ea_scope.apply_id = exam_result.apply_id
              and ea_scope.patient_id = #{params.applyPatientId}
        )


order by apply_id desc, sort asc, result_id asc
